const cards = require('../demo/cards.js')
const timetables = require('../demo/timetables.js')
const ajax = function (url) {
  if (url === 'card') {
    return new Promise(function (resolve, reject) {
      resolve(cards)
    })
  } else if (url === 'timetable/all') {
    return new Promise(function (resolve, reject) {
      resolve(timetables)
    })
  }
}
export default ajax



